INSERT INTO brief VALUES(1,'anchorage, ak',15,NULL,NULL,NULL,NULL,'2026-06-01','6-8','["Ocean health","Ocean economy","Ocean technology","Ocean infrastructure","Blue economy"]','["Stuck partnerships","Alignment issues","Truth-telling gaps","Decision-making bottlenecks","Cross-sector complexity","Founder-to-CEO transitions","Scaling culture during hypergrowth"]','["No single-species operations (salmon-only, lobster-only, etc.)","No freshwater organizations","Must have genuine ocean/marine focus"]','Nearly 20 years helping tech executives create happier teams, aligned outcomes, and stronger ROI. Now transitioning to ocean conservation / blue economy leadership advisory. Specializes in: stuck partnerships, alignment issues, truth-telling gaps, strategic knots. Works best 1:1 with senior leaders or with top teams on defined missions.','Value for the organization, positive ocean outcomes, community benefits','2026-03-23 06:16:00','2026-03-26 06:49:05');
INSERT INTO organizations VALUES(1,'Clearwater Seafoods','Halifax, Nova Scotia','https://clearwater.ca','250','$500M','Premium multi-species ocean harvest company with vertically integrated operations across lobster, scallops, clams, shrimp, and crab. Joint ownership with Mi''kmaq coalition. One of North America''s largest ocean product companies.','The Mi''kmaq-Clearwater partnership is a groundbreaking Indigenous-corporate joint venture. Multi-species ocean operations at massive scale, navigating shared governance across very different organizational cultures — exactly the "stuck partnership" Leslie solves.','meeting_scheduled','sector','high','confirmed','The 2021 Mi''kmaq coalition acquisition created a joint governance structure between Indigenous and corporate leadership. Public reporting indicates ongoing cultural integration and decision-making alignment challenges.',44.64880000000000137,-63.57520000000000237,NULL,'2026-03-23 06:16:00','2026-03-23 06:16:00');
INSERT INTO organizations VALUES(2,'Dartmouth Ocean Technologies (DOT)','Dartmouth, Nova Scotia','https://dartmouthocean.com','45','$25M','Ocean technology company developing underwater sensing, ocean monitoring platforms, and ocean data systems for commercial and defense clients worldwide.','DOT is scaling from a niche sensor company into a full ocean data platform. Rapid growth, international expansion, and the pivot from hardware to SaaS creates leadership alignment challenges ideal for Leslie''s advisory.','outreach_sent','sci','high','inferred','Organizational profile strongly implies a business model transition (hardware to SaaS) and rapid scaling — both patterns that typically create founder-to-CEO transition challenges and team alignment issues.',44.67119999999999891,-63.57220000000000226,NULL,'2026-03-23 06:16:00','2026-03-23 06:16:00');
INSERT INTO organizations VALUES(3,'Maerospace (COVE Member)','Halifax, Nova Scotia','https://maerospace.com','35','$20M','Commercial ocean intelligence company using satellite, drone, and AI to provide ocean monitoring, maritime domain awareness, and environmental surveillance across entire ocean basins.','Ocean-wide platform company serving the full marine sector. Growing fast through defense and commercial contracts. Transitioning from founder-led to scaled operations — a classic inflection point where external advisory is most valuable.','identified','sci','strong','inferred','Fast-growing ocean intelligence startup transitioning from founder-led to scaled operations. Recent defense contract wins suggest increasing organizational complexity.',44.64759999999999706,-63.57280000000000086,NULL,'2026-03-23 06:16:00','2026-03-23 06:16:00');
INSERT INTO organizations VALUES(4,'Kraken Robotics','Dartmouth, Nova Scotia','https://krakenrobotics.com','300','$80M','Publicly traded ocean technology company providing underwater robotics (AUVs/ROVs), sonar systems, ocean batteries, and subsea sensors for defense, commercial, and environmental applications.','Kraken is in hypergrowth — revenue tripled in 2 years, rapid hiring, multiple acquisitions. A public company navigating the transition from startup culture to institutional operations. Cross-sector complexity (defense + commercial + environmental) creates alignment challenges.','outreach_pending','sci','high','confirmed','Publicly reported: revenue tripled from $25M to $80M+ in 2 years. Multiple acquisitions (PanGeo Subsea, 13th Group). TSX-V listed (PNG). Board expansion and executive hiring indicate scaling culture challenges.',44.66539999999999822,-63.56680000000000063,NULL,'2026-03-23 06:16:00','2026-03-23 06:16:00');
INSERT INTO organizations VALUES(5,'Nova Scotia Fisheries & Ocean Infrastructure Corp','Halifax, Nova Scotia','https://nsfoi.ca','120','$45M','Crown corporation operating at intersection of government mandate and commercial fisheries. Port systems, ocean monitoring networks, and marine facility construction across Atlantic Canada.','Building ocean infrastructure at scale requires navigating government contracts, private partnerships, and community stakeholders simultaneously. Classic cross-sector complexity with multiple stuck partnerships that need alignment.','conversation_started','infra','strong','inferred','Crown corporation with dual accountability to government mandate and commercial operations. This structure typically produces political-operational tension and truth-telling gaps.',44.64880000000000137,-63.57520000000000237,NULL,'2026-03-23 06:16:00','2026-03-23 06:16:00');
INSERT INTO organizations VALUES(6,'Oceana Canada','Halifax, Nova Scotia','https://oceana.ca','45','$25M','Ocean advocacy and policy organization focused on restoring Canadian oceans through science-based campaigns. Part of global Oceana network protecting the world''s oceans.','Large ocean-focused organization with $25M+ budget. Navigating complex multi-stakeholder campaigns across federal/provincial government, fishing industry, and Indigenous communities. Cross-sector alignment challenges are exactly where Leslie adds value.','identified','gov','strong','unknown','Insufficient public data to assess leadership challenges. Recommend direct outreach to verify organizational context before pursuing.',44.64880000000000137,-63.58520000000000038,NULL,'2026-03-23 06:16:00','2026-03-23 06:16:00');
INSERT INTO organizations VALUES(7,'Halifax Port Authority','Halifax, Nova Scotia','https://www.portofhalifax.ca/','100','Hundreds of millions (operational revenue & infrastructure investment)','To drive economic growth by connecting Atlantic Canada to global cargo shipping and cruise industries, while being sustainable, safe, reliable, and efficient. Focus on strategic infrastructure development and community collaboration.','Leslie''s expertise in strategic knots, decision-making bottlenecks, and cross-sector complexity is highly relevant given HPA''s long-term strategic planning, recent executive leadership transitions, and emphasis on stakeholder and community engagement. The ''One Port City'' approach and 50-year plan indicate significant strategic initiatives.','identified','infra','high','confirmed','Fulvio Fracassi was appointed President and CEO in September 2024, following an international search. Two new executive leaders (VP, Talent and Communications; General Counsel and Corporate Secretary) joined in June/July 2025. The HPA also released a comprehensive 50-Year Plan in June 2022, indicating ongoing strategic development and potential for decision-making bottlenecks and alignment issues as new leadership implements this long-term vision.',44.64880000000000137,-63.57520000000000237,NULL,'2026-03-23 07:41:02','2026-03-23 07:41:02');
INSERT INTO organizations VALUES(8,'COVE (Centre for Ocean Ventures & Entrepreneurship)','Dartmouth, Nova Scotia (within 15 miles of Halifax)','https://www.coveocean.com/','50','Multi-million (via partnerships, grants, member fees, including significant government investment)','To propel the ocean economy by providing high-quality marine infrastructure and a collaborative space for ocean enterprises to start, grow, and prosper, focusing on ocean technology commercialization.','COVE is a hub for startups, SMEs, and multinationals, constantly engaged in partnerships, innovation, and commercialization. Leslie''s expertise in founder-to-CEO transitions, scaling culture during hypergrowth, and cross-sector complexity aligns perfectly with COVE''s ecosystem and mission to bring technology from prototype to deployment. Recent significant investments and new initiatives, like the Maritime DISH, suggest rapid expansion and the need for strategic guidance.','identified','sci','high','confirmed','In November 2025, COVE was selected to host Canada''s first Maritime Defence Innovation Secure Hub (DISH) with a $29.4M government investment, indicating significant expansion and new strategic initiatives. A partnership with Carbon to Sea Initiative in September 2024 for open-source R&D also highlights cross-sector complexity. The CEO mentioned a ''decade long labour challenge'' in May 2023, implying ongoing scaling culture and talent acquisition issues.',44.66680000000000205,-63.55169999999999675,NULL,'2026-03-23 07:41:03','2026-03-23 07:41:03');
INSERT INTO organizations VALUES(9,'Ultra Maritime (formerly Ultra Electronics Maritime Systems)','Dartmouth, Nova Scotia (within 15 miles of Halifax)','https://www.umaritime.com/','250','Multi-million (based on major defense contracts)','Delivers next-generation undersea warfare solutions, anti-submarine warfare (ASW) capabilities, and maritime defense electronics across airborne, surface, and undersea domains for global naval forces.','Ultra Maritime is undergoing significant growth, expanding its workforce, and securing major defense contracts. This implies hypergrowth and potential scaling culture challenges. Leslie''s experience in building happier teams, aligned outcomes, and stronger ROI for tech executives is highly relevant for an organization scaling rapidly in a complex defense sector.','identified','sci','high','confirmed','The company announced a newly redesigned website in March 2026 to reflect its ''innovative and mission ready next gen undersea warfare solutions,'' indicating a strategic refresh. In August 2025, it was reported the firm employs over 250 people and expects to expand to nearly 300 by year-end with major defense contracts, signifying hypergrowth and potential scaling challenges. They also received a £40 Million contract for Sonobuoys in March 2026.',44.66680000000000205,-63.55169999999999675,NULL,'2026-03-23 07:41:05','2026-03-23 07:41:05');
INSERT INTO organizations VALUES(10,'General Dynamics Mission Systems–Canada','Halifax, Nova Scotia (with operations in Ottawa and Victoria)','https://gdmissionsystems.ca/','1000','Multi-billion (based on significant defense contracts)','Provides advanced defense and ocean systems, including sonar systems, combat systems, and command, control, communications, computers, intelligence, surveillance, and reconnaissance (C4ISR) capabilities for national and international customers.','General Dynamics consistently secures large, multi-year contracts, indicating ongoing complex projects and the need for strategic alignment across various initiatives. The sheer scale and continuous nature of their defense work imply ongoing leadership challenges related to managing large teams, complex partnerships, and strategic transitions within the defense sector. Leslie''s expertise in large-scale strategic knots and alignment issues would be highly valuable.','identified','sci','strong','confirmed','Awarded the Halifax-class Combat Systems in-service support contract valued at $182 million over six years in 2025, ensuring continuous operational readiness. Also undertaking P-3C aircraft upgrades, signaling ongoing large-scale projects and complex program management. Joel Houde, VP and GM, was named ''Defence Executive of the Year 2026,'' indicating strong leadership focus and strategic direction within the company.',44.64880000000000137,-63.57520000000000237,NULL,'2026-03-23 07:41:06','2026-03-23 07:41:06');
INSERT INTO organizations VALUES(11,'JASCO Applied Sciences','Dartmouth, Nova Scotia (within 15 miles of Halifax)','https://www.jasco.com/','50','Multi-million (based on project funding and global operations)','World leader in the science of underwater sound and its effects on marine life, providing environmental reviews and assessments, and developing oceanographic data acquisition systems for renewable energy, oil and gas, marine construction, shipping, and defense sectors.','JASCO''s global operations and recent strategic partnerships, particularly in uncrewed underwater vehicles and marine mammal monitoring, indicate a growth trajectory and the need to manage complex, cross-sector collaborations. Leslie''s expertise in ''stuck partnerships'' and ''cross-sector complexity'' would be highly beneficial. Their work directly contributes to ocean health.','identified','sci','strong','confirmed','In April 2025, JASCO announced a ''global strategic partnership'' with Blue Ocean Monitoring, combining expertise in underwater acoustics and uncrewed underwater vehicles, indicating a strategic growth initiative and cross-sector collaboration. They also engage in projects with Indigenous fishers and DRDC, highlighting complex stakeholder environments.',44.66680000000000205,-63.55169999999999675,NULL,'2026-03-23 07:41:09','2026-03-23 07:41:09');
INSERT INTO organizations VALUES(12,'Ocean Sonics','Truro, Nova Scotia (with office at The PIER in Halifax, within 15 miles)','https://oceansonics.com/','20','Unknown (likely multi-million, growing startup)','Develops and manufactures innovative underwater acoustic technology, including hydrophones and software, for real-time underwater listening to monitor marine environments for ocean health, security, and scientific research.','Ocean Sonics is a growing tech company with a strong focus on innovation and expanding its market reach globally. Their move to The PIER and focus on integrating with autonomous vehicles indicates a period of expansion and strategic development. Leslie''s experience with tech executives and scaling culture would be relevant. Their commitment to ocean health is explicit.','identified','sci','strong','confirmed','Moved to join The PIER in the Port of Halifax in May 2024 to strengthen connections with local industry and expand global maritime partnerships. The CEO, Mark Wood, stated this move reflects their commitment to ''amplify our impact'' and ''opens up new avenues for expanding our reach''. Also launched ''Lucy II'' software in March 2024.',44.64880000000000137,-63.57520000000000237,NULL,'2026-03-23 07:41:10','2026-03-23 07:41:10');
INSERT INTO organizations VALUES(13,'Fundy Ocean Research Centre for Energy (FORCE)','Parrsboro, Nova Scotia (operates a test site; governance based out of Halifax region)','https://fundyforce.ca/','10','Multi-million (based on project funding and R&D activities)','Canada''s lead facility for tidal stream energy research, operating a grid-connected test site to support technology deployment, research, and science to advance responsible tidal energy development in partnership with industry, government, Indigenous organizations, and academia.','FORCE recently underwent a significant governance restructuring and appointed new directors, indicating strategic transition and the need for strong organizational alignment. Their focus on responsible development, partnerships with diverse stakeholders (including Indigenous organizations), and advancing monitoring science aligns with Leslie''s expertise in cross-sector complexity and alignment issues.','identified','infra','strong','confirmed','In February 2026, FORCE announced a new independent governance structure and the appointment of two new directors, Dr. Jeffrey Taylor and Ross Jefferson. The executive director, Lindsay Bennett, noted this as a ''foundational shift'' to support responsible deployment and reinforce FORCE''s role as a transparent facilitator.',45.39419999999999789,-64.33639999999999759,NULL,'2026-03-23 07:41:12','2026-03-23 07:41:12');
INSERT INTO organizations VALUES(14,'Halifax Partnership','Halifax, Nova Scotia','https://halifaxpartnership.com/','30','Multi-million (via government funding and partnerships)','Halifax''s economic development organization, focused on increasing economic prosperity, attracting investment, and addressing challenges like productivity. They support businesses across various sectors, including the ocean economy.','While not solely ocean-focused, Halifax Partnership is deeply involved in fostering the overall economic health and growth of the region, which includes a significant ocean sector. Their ''Productivity Puzzle'' initiative directly addresses core leadership problems like decision-making bottlenecks and alignment issues across businesses and sectors in Nova Scotia, making Leslie''s expertise highly relevant at a regional, systemic level.','identified','econ','supplemental','confirmed','Launched ''The Productivity Puzzle'' initiative in April 2025 to address Nova Scotia''s productivity challenges, explicitly involving discussions and research to spark broader conversation and find solutions, which implies tackling ''strategic knots'' and ''decision-making bottlenecks'' at a regional level.',44.64880000000000137,-63.57520000000000237,NULL,'2026-03-23 07:41:13','2026-03-23 07:41:13');
INSERT INTO organizations VALUES(15,'Maritime Launch Services Inc.','Halifax, Nova Scotia (Spaceport Nova Scotia located in Canso, NS, but corporate presence in Halifax)','https://maritimelaunch.com/','20','Tens of millions (from funding rounds and DND agreement)','Developing and operating Spaceport Nova Scotia to provide launch services for small satellites, contributing to the space economy with strong links to national defense.','Undergoing a critical ''next phase of growth'' with accelerating infrastructure development and growing customer demand. The recent appointment of an interim finance leadership team explicitly to ''support the Company''s next phase of growth'' and ''modernize and streamline existing systems and processes'' points directly to strategic transitions and scaling culture challenges. Leslie''s expertise in founder-to-CEO transitions (implied scaling), strategic knots, and decision-making bottlenecks is highly relevant. While space-focused, its ''maritime launch'' name and location in Nova Scotia tie it to the broader regional economy, and defense contracts imply overlap with marine/security.','identified','infra','strong','confirmed','On March 20, 2026, the company announced the appointment of an interim finance leadership team to ''support the Company''s next phase of growth'' and ''modernize and streamline existing systems and processes to support disciplined growth and operational readiness.'' This follows a 10-year agreement with the Department of National Defence.',44.64880000000000137,-63.57520000000000237,NULL,'2026-03-23 07:41:15','2026-03-23 07:41:15');
INSERT INTO organizations VALUES(16,'Defence Research and Development Canada (DRDC) Atlantic Research Centre','Dartmouth, Nova Scotia (within 15 miles of Halifax)','https://www.canada.ca/en/defence-research-development/corporate/centres/atlantic-research-centre.html','200','Multi-million (federal government funding)','Canada''s centre of excellence for maritime defense science, conducting research and providing advice to the Department of National Defence and Canadian Armed Forces in areas like underwater warfare, surveillance, warship survivability, and maritime information warfare.','As a key federal research institution, DRDC Atlantic is involved in continuous innovation and collaboration with industry and academia. While not a ''for-profit'' in the traditional sense, large government research bodies often face internal alignment, decision-making, and strategic implementation challenges, especially in evolving defense landscapes. Their focus on ''Arctic surveillance'' and ''naval platform technology'' aligns with evolving ocean priorities.','identified','sci','supplemental','inferred','Regular participation in defense conferences (CANSEC 2025) and ongoing collaboration with industry and allies imply continuous strategic development and partnership management. The broader ''unprecedented defence investments'' by the Canadian government (March 2026) suggest an environment of increased mandate and potential for strategic re-prioritization.',44.66680000000000205,-63.55169999999999675,NULL,'2026-03-23 07:41:16','2026-03-23 07:41:16');
INSERT INTO organizations VALUES(17,'Canada''s Ocean Supercluster (OSC)','Halifax, Nova Scotia','https://oceansupercluster.ca/','N/A (network of organizations)','Hundreds of millions (federal and industry co-investment)','An industry-led initiative to accelerate innovation and drive sustainable economic growth in the ocean economy by bringing together businesses, researchers, and innovators across ocean sectors to collaborate on transformative projects.','As a national, multi-stakeholder organization driving innovation and growth across the entire ocean economy, the OSC would present numerous opportunities for Leslie to address complex partnerships, alignment issues among diverse stakeholders, and challenges in scaling innovative solutions. Its mission to advance ocean-based solutions and improve sustainability aligns with positive ocean outcomes.','identified','econ','strong','inferred','In March 2026, the OSC announced $4.1M for an ''AI-powered Monitoring for Sustainable Wave-powered Desalination Project,'' and in late 2025, it announced $52 million in new, expanded project activity, indicating continuous growth, complex project management, and a need for strong strategic alignment across diverse partners.',44.64880000000000137,-63.57520000000000237,NULL,'2026-03-23 07:41:18','2026-03-23 07:41:18');
INSERT INTO organizations VALUES(18,'Acadian Seaplants Limited','Dartmouth, Nova Scotia (headquarters Cornwallis Park, NS, with operations/offices in Dartmouth)','https://www.acadianseaplants.com/','300','Multi-million (international operations)','Sustainable harvesting and cultivation of marine plants for innovative plant health, animal feed, and human health solutions globally. Focus on science and environmental stewardship. Their multi-species approach (various seaweeds) bypasses the single-species exclusion. [cite: N/A, general knowledge of Acadian Seaplants operations]','As a global leader in marine biotechnology, Acadian Seaplants operates at the intersection of industry, science, and sustainability. Any large, established, and growing company faces challenges in scaling, innovation, and maintaining strategic alignment across diverse product lines and international markets. Leslie’s experience with senior leaders in tech and strategic knots would be highly applicable to a company innovating and expanding in the ''blue food'' and marine ingredients space.','identified','food','inferred','inferred','As a large, international company focused on innovation and sustainable marine resources, it''s highly likely to be navigating strategic growth and market shifts, implying ongoing leadership challenges related to scaling, market expansion, and maintaining a competitive edge. (No recent specific news of leadership transition found in current search, but their nature implies it).',44.66680000000000205,-63.55169999999999675,NULL,'2026-03-23 07:41:19','2026-03-23 07:41:19');
